import { memo } from "react";
import { useQuery } from "@tanstack/react-query";
import { useTranslation } from "react-i18next";
import { Sparkles } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import PostGridCard from "./PostGridCard";
import { Skeleton } from "@/components/ui/skeleton";

interface RelatedPostsProps {
  currentPostId: string;
  authorId?: string;
  postType?: string;
  activityId?: string | null;
  limit?: number;
}

const RelatedPosts = memo(({ currentPostId, authorId, postType, activityId, limit = 6 }: RelatedPostsProps) => {
  const { t } = useTranslation();

  const { data: posts, isLoading } = useQuery({
    queryKey: ["related-posts", currentPostId, authorId, postType, activityId],
    queryFn: async () => {
      const results: any[] = [];

      // 1. Same activity posts
      if (activityId) {
        const { data } = await supabase
          .from("community_posts")
          .select(`
            *,
            author:profiles!community_posts_author_id_fkey(id, display_name, avatar_url),
            post_restaurants(restaurant:restaurants(id, name, name_en, name_pt))
          `)
          .eq("activity_id", activityId)
          .eq("status", "approved")
          .neq("id", currentPostId)
          .order("created_at", { ascending: false })
          .limit(limit);
        if (data) results.push(...data);
      }

      // 2. Same author posts (if not enough)
      if (results.length < limit && authorId) {
        const existingIds = new Set([currentPostId, ...results.map((r) => r.id)]);
        const { data } = await supabase
          .from("community_posts")
          .select(`
            *,
            author:profiles!community_posts_author_id_fkey(id, display_name, avatar_url),
            post_restaurants(restaurant:restaurants(id, name, name_en, name_pt))
          `)
          .eq("author_id", authorId)
          .eq("status", "approved")
          .neq("id", currentPostId)
          .order("created_at", { ascending: false })
          .limit(limit);
        if (data) {
          for (const p of data) {
            if (!existingIds.has(p.id)) {
              results.push(p);
              existingIds.add(p.id);
            }
          }
        }
      }

      // 3. Same type popular posts (if still not enough)
      if (results.length < limit) {
        const existingIds = new Set([currentPostId, ...results.map((r) => r.id)]);
        const { data } = await supabase
          .from("community_posts")
          .select(`
            *,
            author:profiles!community_posts_author_id_fkey(id, display_name, avatar_url),
            post_restaurants(restaurant:restaurants(id, name, name_en, name_pt))
          `)
          .eq("status", "approved")
          .eq("post_type", postType || "post")
          .neq("id", currentPostId)
          .order("likes_count", { ascending: false })
          .limit(limit * 2);
        if (data) {
          for (const p of data) {
            if (!existingIds.has(p.id) && results.length < limit) {
              results.push(p);
              existingIds.add(p.id);
            }
          }
        }
      }

      return results.slice(0, limit).map((post: any) => ({
        ...post,
        restaurants: post.post_restaurants?.map((pr: any) => pr.restaurant).filter(Boolean) || [],
      }));
    },
    enabled: !!currentPostId,
  });

  if (isLoading) {
    return (
      <div className="mt-8">
        <div className="flex items-center gap-2 mb-4">
          <Skeleton className="h-5 w-5 rounded" />
          <Skeleton className="h-5 w-24" />
        </div>
        <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
          {Array.from({ length: 3 }).map((_, i) => (
            <Skeleton key={i} className="aspect-square rounded-lg" />
          ))}
        </div>
      </div>
    );
  }

  if (!posts || posts.length === 0) return null;

  return (
    <div className="mt-8 pt-6 border-t">
      <div className="flex items-center gap-2 mb-4">
        <Sparkles className="w-5 h-5 text-primary" />
        <h3 className="text-base font-semibold text-foreground">
          {t("community.relatedPosts")}
        </h3>
      </div>
      <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
        {posts.map((post: any) => (
          <PostGridCard key={post.id} post={post} />
        ))}
      </div>
    </div>
  );
});

RelatedPosts.displayName = "RelatedPosts";

export default RelatedPosts;
